challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The Access and Mobility Management Function (AMF) container has exited. This is a fatal control-plane failure that prevents UEs from registering with the network, leading to a complete loss of PDU session establishment and a collapse of all user-plane and subsequent IMS activity.",
      "primary_suspect_nf": "amf",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "Check the status of the 'amf' container.",
          "expected_if_hypothesis_holds": "The 'amf' container is reported as 'exited' or otherwise not running.",
          "falsifying_observation": "The 'amf' container is reported as 'running'."
        },
        {
          "tool": "check_process_listeners",
          "args_hint": "container=\"amf\"",
          "expected_if_hypothesis_holds": "The tool returns an error or an empty list, as no process should be listening for connections in an exited container.",
          "falsifying_observation": "The tool returns a list of active listening ports, which would indicate the AMF process is running."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from=\"nr_gnb\", to_ip=\"amf\"",
          "expected_if_hypothesis_holds": "100% packet loss. The AMF container is down and its IP should be unreachable.",
          "falsifying_observation": "Normal RTT (<10ms) and 0% packet loss, indicating the container is up and its network stack is responsive."
        }
      ],
      "notes": "This plan directly tests the central claim of the hypothesis: that the AMF container has exited. The probes verify this at the infrastructure, process, and network layers."
    }
  ]
}

